import boto3
import json

QUEUE_NAME = "your-queue-name"
AWS_ACCESS_KEY_ID = 'your-access-key'
AWS_SECRET_ACCESS_KEY = 'your-secret-key'
REGION_NAME = 'us-west-2'

sqs = boto3.client('sqs', aws_access_key_id=AWS_ACCESS_KEY_ID,
                    aws_secret_access_key=AWS_SECRET_ACCESS_KEY, region_name=REGION_NAME)

def publish_to_queue(data):
    response = sqs.send_message(QueueUrl=QUEUE_NAME, MessageBody=json.dumps(data))
    print(f'Message with message ID: {response["MessageId"]} sent to the queue')

user_data = {
    'email': 'user@example.com',
    'phone_number': '123-456-7890',
    'address': {'street': '123 Main St.', 'city': 'Anytown'}
}
publish_to_queue(user_data)